 17→std::vector<std::string> SafeHyperJob::run(void) {
 18→  // TODO: Rework
 19→  current = new Matter(pot, params);
 20→  reactant = new Matter(pot, params);
 21→  saddle = new Matter(pot, params);
 22→  product = new Matter(pot, params);
 23→  final_img = new Matter(pot, params);
 24→  final_img_tmp = new Matter(pot, params);
 25→
 26→  minimizeFCalls = mdFCalls = refineFCalls = dephaseFCalls = 0;
