 64→int SafeHyperJob::dynamics() {
 65→  bool transitionFlag = false, recordFlag = true, stopFlag = false,
 66→       firstTransitFlag = false;
 67→  long nFreeCoord = reactant->numberOfFreeAtoms() * 3;
 68→  long mdBufferLength, refFCalls;
 69→  long step = 0, refineStep,
 70→       newStateStep = 0; // check that newStateStep is set before used
 71→  long nCheck = 0, nRecord = 0, nBoost = 0, nState = 0;
 72→  long StateCheckInterval, RecordInterval;
 73→  double kinE, kinT, avgT, varT;
 74→  double kB = params.constants.kB;
 75→  double correctedTime = 0.0, sumCorrectedTime = 0.0, firstTransitionTime = 0.0;
 76→  double Temp = 0.0, sumT = 0.0, sumT2 = 0.0;
 77→  double sumboost = 0.0, boost = 1.0, boostPotential = 0.0;
 78→  double transitionTime_current = 0.0, transitionTime_pre = 0.0;
 79→  AtomMatrix velocity;
 80→
 81→  minCorrectedTime = 1.0e200;
 82→  StateCheckInterval =
 83→      int(params.parallel_replica_options.state_check_interval /
 84→          params.dynamics_options.time_step);
 85→  RecordInterval = int(params.parallel_replica_options.record_interval /
 86→                       params.dynamics_options.time_step);
 87→  Temp = params.main_options.temperature;
 88→  newStateFlag = metaStateFlag = false;
 89→
 90→  mdBufferLength = long(StateCheckInterval / RecordInterval);
 91→  Matter *mdBuffer[mdBufferLength];
 92→  for (long i = 0; i < mdBufferLength; i++) {
 93→    mdBuffer[i] = new Matter(pot, params);
 94→  }
 95→  timeBuffer = new double[mdBufferLength];
 96→  biasBuffer = new double[mdBufferLength];
 97→
 98→  Dynamics safeHyper(current, params);
 99→  BondBoost bondBoost(current, params);
100→
101→  if (params.hyperdynamics_options.bias_potential ==
102→      Hyperdynamics::BOND_BOOST) {
103→    bondBoost.initialize();
104→  }
105→
106→  safeHyper.setThermalVelocity();
107→
108→  // dephase the trajectory so that it is thermal and independent of others
109→  // refFCalls = Potential::fcalls;
110→  dephase();
111→  // dephaseFCalls = Potential::fcalls - refFCalls;
112→
113→  SPDLOG_LOGGER_DEBUG(
114→      log,
115→      "Starting MD run\nTemperature: {:.2f} Kelvin\n"
116→      "Total Simulation Time: {:.2f} fs\nTime Step: {:.2f} fs\nTotal Steps: {}",
117→      Temp,
118→      params.dynamics_options.steps * params.dynamics_options.time_step *
119→          params.constants.timeUnit,
120→      params.dynamics_options.time_step * params.constants.timeUnit,
121→      params.dynamics_options.steps);
122→  SPDLOG_LOGGER_DEBUG(log, "MD buffer length: {}", mdBufferLength);
123→
124→  long tenthSteps = params.dynamics_options.steps / 10;
125→  // This prevents and edge case division by zero if mdSteps is < 10
126→  if (tenthSteps == 0) {
127→    tenthSteps = params.dynamics_options.steps;
128→  }
129→
130→  // loop dynamics iterations until some condition tells us to stop
131→  while (!stopFlag) {
132→    if ((params.hyperdynamics_options.bias_potential ==
133→         Hyperdynamics::BOND_BOOST) &&
134→        !newStateFlag) {
135→      // GH: boost should be a unitless factor, multipled by TimeStep to get the
136→      // boosted time
137→      // SPDLOG_LOGGER_DEBUG(log, "step= {} , boost = {:.5f}", step,
138→      // bondBoost.boost());
139→      boostPotential = bondBoost.boost();
140→      boost = 1.0 * exp(boostPotential / kB / Temp);
141→      time += params.dynamics_options.time_step * boost;
142→      if (boost > 1.0) {
143→        sumboost += boost;
144→        nBoost++;
145→      }
146→    }
147→
148→    kinE = current->getKineticEnergy();
149→    kinT = (2.0 * kinE / nFreeCoord / kB);
150→    sumT += kinT;
151→    sumT2 += kinT * kinT;
152→    // SPDLOG_LOGGER_DEBUG(log, "steps = {:10} temp = {:10.5f}", step, kinT);
153→
154→    safeHyper.oneStep();
155→    mdFCalls++;
156→
157→    nCheck++; // count up to
158→              // params.parallel_replica_options.state_check_interval before
159→              // checking for a transition
160→    step++;
161→    // SPDLOG_LOGGER_DEBUG(log, "step = {:4}, time = {:10.4f}", step, time);
162→    //  standard conditions; record mater object in the transition buffer
163→    if (params.parallel_replica_options.refine_transition && recordFlag &&
164→        !newStateFlag) {
165→      if (nCheck % RecordInterval == 0) {
166→        *mdBuffer[nRecord] = *current;
167→        timeBuffer[nRecord] = time;
168→        biasBuffer[nRecord] = boostPotential;
169→        nRecord++; // current location in the buffer
170→      }
171→    }
172→
173→    // time to do a state check; if a transiton if found, stop recording
174→    if ((nCheck == StateCheckInterval) && !newStateFlag) {
175→      nCheck = 0;  // reinitialize check state counter
176→      nRecord = 0; // restart the buffer
177→      refFCalls = Potential::fcalls;
178→      transitionFlag = checkState(current, reactant);
179→      // minimizeFCalls += Potential::fcalls - refFCalls;
180→      if (transitionFlag == true) {
181→        nState++;
182→        SPDLOG_LOGGER_DEBUG(log, "New State {}: ", nState);
183→        *final_img_tmp = *current;
184→        transitionTime = time;
185→        newStateStep = step; // remember the step when we are in a new state
186→        transitionStep = newStateStep;
187→        firstTransitFlag = 1;
188→      }
189→    }
190→    // printf("step=%ld, time=%lf, biasPot=%lf\n",step,time,boostPotential);
191→    // Refine transition step
192→
193→    if (transitionFlag) {
194→      // SPDLOG_LOGGER_DEBUG(log, "[Parallel Replica] Refining transition
195→      // time.");
196→      refFCalls = Potential::fcalls;
197→      refineStep = refine(mdBuffer, mdBufferLength, reactant);
198→
199→      transitionStep =
200→          newStateStep - StateCheckInterval + refineStep * RecordInterval;
201→      transitionTime_current = timeBuffer[refineStep];
202→      transitionTime = transitionTime_current - transitionTime_pre;
203→      transitionTime_pre = transitionTime_current;
204→      transitionPot = biasBuffer[refineStep];
205→      correctedTime = transitionTime * exp((-1) * transitionPot / kB / Temp);
206→      sumCorrectedTime += correctedTime;
207→      if (nState == 1) {
208→        firstTransitionTime = transitionTime;
209→      }
210→      // reverse the momenten;
211→      *current = *mdBuffer[refineStep - 1];
212→      velocity = current->getVelocities();
213→      velocity = velocity * (-1);
214→      current->setVelocities(velocity);
215→
216→      if (correctedTime < minCorrectedTime) {
217→        minCorrectedTime = correctedTime;
218→        *saddle = *mdBuffer[refineStep];
219→        *final_img = *final_img_tmp;
220→      }
221→      SPDLOG_LOGGER_DEBUG(
222→          log,
223→          "tranisitonTime= {:.3e} s, biasPot= {:.3f} eV, "
224→          "correctedTime= {:.3e} s, "
225→          "sumCorrectedTime= {:.3e} s, minCorTime= {:.3e} s",
226→          transitionTime * 1e-15 * params.constants.timeUnit, transitionPot,
227→          correctedTime * 1e-15 * params.constants.timeUnit,
228→          sumCorrectedTime * 1e-15 * params.constants.timeUnit,
229→          minCorrectedTime * 1.0e-15 * params.constants.timeUnit);
230→
231→      // refineFCalls += Potential::fcalls - refFCalls;
232→      transitionFlag = false;
233→    }
234→
235→    // we have run enough md steps; time to stop
236→    if (firstTransitFlag && sumCorrectedTime > firstTransitionTime) {
237→      stopFlag = true;
238→      newStateFlag = true;
239→    }
240→
241→    // stdout Progress
242→    if ((step % tenthSteps == 0) || (step == params.dynamics_options.steps)) {
243→      double maxAtomDistance = current->perAtomNorm(*reactant);
244→      SPDLOG_LOGGER_DEBUG(
245→          log, "progress: {:.0f}%, max displacement: {:.3f}, step {} / {}",
246→          static_cast<double>(100.0 * step / params.dynamics_options.steps),
247→          maxAtomDistance, step, params.dynamics_options.steps);
248→    }
249→  }
250→
251→  // calculate averages
252→  avgT = sumT / step;
253→  varT = sumT2 / step - avgT * avgT;
254→
255→  if (nBoost > 0) {
256→    SPDLOG_LOGGER_DEBUG(log,
257→                        "Temperature : Average = {:.6f} ; Stddev = {:.6f} ; "
258→                        "Factor = {:.6f}; Boost = {:.6f}",
259→                        avgT, sqrt(varT), varT / avgT / avgT * nFreeCoord / 2,
260→                        sumboost / nBoost);
261→  } else {
262→    SPDLOG_LOGGER_DEBUG(
263→        log,
264→        "Temperature : Average = {:.6f} ; Stddev = {:.6f} ; Factor = {:.6f}",
265→        avgT, sqrt(varT), varT / avgT / avgT * nFreeCoord / 2);
266→  }
267→  if (std::isfinite(avgT) == 0) {
268→    SPDLOG_LOGGER_DEBUG(log,
269→                        "Infinite average temperature, something went wrong!");
270→    newStateFlag = false;
271→  }
272→
273→  *product = *final_img;
274→  // new state was detected; determine refined transition time
275→  for (long i = 0; i < mdBufferLength; i++) {
276→    delete mdBuffer[i];
277→  }
278→  delete[] timeBuffer;
279→  delete[] biasBuffer;
280→
281→  if (newStateFlag) {
282→    return 1;
283→  } else {
284→    return 0;
285→  }
286→}
