288→void SafeHyperJob::saveData(int status) {
289→  FILE *fileResults, *fileReactant;
290→
291→  std::string resultsFilename("results.dat");
292→  returnFiles.push_back(resultsFilename);
293→
294→  fileResults = fopen(resultsFilename.c_str(), "wb");
295→  // long totalFCalls = minimizeFCalls + mdFCalls + dephaseFCalls +
296→  // refineFCalls;
297→
298→  fprintf(fileResults, "%s potential_type\n",
299→          std::string{magic_enum::enum_name<PotType>(
300→                          params.potential_options.potential)}
301→              .c_str());
302→  fprintf(fileResults, "%ld random_seed\n", params.main_options.randomSeed);
303→  fprintf(fileResults, "%lf potential_energy_reactant\n",
304→          reactant->getPotentialEnergy());
305→  // fprintf(fileResults, "%ld total_force_calls\n", totalFCalls);
306→  fprintf(fileResults, "%ld force_calls_dephase\n", dephaseFCalls);
307→  fprintf(fileResults, "%ld force_calls_dynamics\n", mdFCalls);
308→  fprintf(fileResults, "%ld force_calls_minimize\n", minimizeFCalls);
309→  // fprintf(fileResults, "%ld force_calls_refine\n", refineFCalls);
310→
311→  //    fprintf(fileResults, "%d termination_reason\n", status);
312→  fprintf(fileResults, "%d transition_found\n", (newStateFlag) ? 1 : 0);
313→
314→  if (newStateFlag) {
315→    fprintf(fileResults, "%e transition_time_s\n",
316→            minCorrectedTime * 1.0e-15 * params.constants.timeUnit);
317→    fprintf(fileResults, "%lf potential_energy_product\n",
318→            product->getPotentialEnergy());
319→    fprintf(fileResults, "%lf moved_distance\n",
320→            product->distanceTo(*reactant));
321→  }
322→
323→  fprintf(fileResults, "%e simulation_time_s\n",
324→          time * 1.0e-15 * params.constants.timeUnit);
325→  fprintf(fileResults, "%lf speedup\n",
326→          time / params.dynamics_options.steps /
327→              params.dynamics_options.time_step);
328→
329→  fclose(fileResults);
330→
331→  std::string reactantFilename("reactant.con");
332→  returnFiles.push_back(reactantFilename);
333→  fileReactant = fopen(reactantFilename.c_str(), "wb");
334→  reactant->matter2con(fileReactant);
335→  fclose(fileReactant);
336→
337→  if (newStateFlag) {
338→    FILE *fileProduct;
339→    std::string productFilename("product.con");
340→    returnFiles.push_back(productFilename);
341→
342→    fileProduct = fopen(productFilename.c_str(), "wb");
343→    product->matter2con(fileProduct);
344→    fclose(fileProduct);
345→
346→    if (params.parallel_replica_options.refine_transition) {
347→      FILE *fileSaddle;
348→      std::string saddleFilename("saddle.con");
349→      returnFiles.push_back(saddleFilename);
350→
351→      fileSaddle = fopen(saddleFilename.c_str(), "wb");
352→      saddle->matter2con(fileSaddle);
353→      fclose(fileSaddle);
354→    }
355→  }
356→  return;
357→}
