359→void SafeHyperJob::dephase() {
360→  bool transitionFlag = false;
361→  long step, stepNew, loop;
362→  long DephaseSteps;
363→  long dephaseBufferLength, dephaseRefineStep;
364→  AtomMatrix velocity;
365→
366→  DephaseSteps = int(params.parallel_replica_options.dephase_time /
367→                     params.dynamics_options.time_step);
368→  Dynamics dephaseDynamics(current, params);
369→  SPDLOG_LOGGER_DEBUG(log, "Dephasing for {:.2f} fs",
370→                      params.parallel_replica_options.dephase_time *
371→                          params.constants.timeUnit);
372→
373→  step = stepNew = loop = 0;
374→
375→  while (step < DephaseSteps) {
376→    // this should be allocated once, and of length DephaseSteps
377→    dephaseBufferLength = DephaseSteps - step;
378→    loop++;
379→    Matter *dephaseBuffer[dephaseBufferLength];
380→
381→    for (long i = 0; i < dephaseBufferLength; i++) {
382→      dephaseBuffer[i] = new Matter(pot, params);
383→      dephaseDynamics.oneStep();
384→      *dephaseBuffer[i] = *current;
385→    }
386→
387→    transitionFlag = checkState(current, reactant);
388→
389→    if (transitionFlag) {
390→      dephaseRefineStep = refine(dephaseBuffer, dephaseBufferLength, reactant);
391→      SPDLOG_LOGGER_DEBUG(log, "loop = {}; dephase refine step = {}", loop,
392→                          dephaseRefineStep);
393→      transitionStep = dephaseRefineStep - 1; // check that this is correct
394→      transitionStep = (transitionStep > 0) ? transitionStep : 0;
395→      SPDLOG_LOGGER_DEBUG(log,
396→                          "Dephasing warning: in a new state, inverse the "
397→                          "momentum and restart "
398→                          "from step {}",
399→                          step + transitionStep);
400→      *current = *dephaseBuffer[transitionStep];
401→      velocity = current->getVelocities();
402→      velocity = velocity * (-1);
403→      current->setVelocities(velocity);
404→      step = step + transitionStep;
405→    } else {
406→      step = step + dephaseBufferLength;
407→      // SPDLOG_LOGGER_DEBUG(log, "Successful dephasing for {:.2f} steps",
408→      // step);
409→    }
410→
411→    for (long i = 0; i < dephaseBufferLength; i++) {
412→      delete dephaseBuffer[i];
413→    }
414→
415→    if ((params.parallel_replica_options.dephase_loop_stop) &&
416→        (loop > params.parallel_replica_options.dephase_loop_max)) {
417→      SPDLOG_LOGGER_DEBUG(
418→          log,
419→          "Reach dephase loop maximum, stop dephasing! Dephased for {} steps",
420→          step);
421→      break;
422→    }
423→    SPDLOG_LOGGER_DEBUG(log, "Successfully Dephased for {:.2f} fs",
424→                        step * params.dynamics_options.time_step *
425→                            params.constants.timeUnit);
426→  }
427→}
428→
429→bool SafeHyperJob::checkState(Matter *current, Matter *reactant) {
430→  Matter tmp(*current);
431→  tmp.relax(true);
432→  if (tmp.compare(*reactant)) {
433→    return false;
434→  }
435→  return true;
436→}
437→
438→long SafeHyperJob::refine(Matter *buff[], long length, Matter *reactant) {
439→  // SPDLOG_LOGGER_DEBUG(log, "[Parallel Replica] Refining transition
440→  // time.\n");
441→
442→  bool midTest;
443→  long min, max, mid;
444→
445→  min = 0;
446→  max = length - 1;
447→
448→  while ((max - min) > 1) {
449→
450→    mid = min + (max - min) / 2;
451→    midTest = checkState(buff[mid], reactant);
452→
453→    if (midTest == false) {
454→      min = mid;
455→    } else if (midTest == true) {
456→      max = mid;
457→    } else {
458→      SPDLOG_LOGGER_CRITICAL(log, "Refine step failed!");
459→      std::exit(1);
460→    }
461→  }
462→
463→  return (min + max) / 2 + 1;
464→}
