276→void GlobalOptimizationJob::randomMove(Matter *matter) {
277→  // create a random displacement
278→  AtomMatrix displacement;
279→  displacement.resize(matter->numberOfAtoms(), 3);
280→  displacement.setZero();
281→  int num = matter->numberOfAtoms();
282→
283→  for (int i = 0; i < num; i++) {
