  long min, max, mid;

  min = 0;
  max = length - 1;

  while ((max - min) > 1) {

    mid = min + (max - min) / 2;
    midTest = checkState(buff[mid], reactant);

    if (midTest == false) {
      min = mid;
    } else if (midTest == true) {
      max = mid;
    } else {
      SPDLOG_LOGGER_CRITICAL(log, "Refine step failed!");
      std::exit(1);
    }
  }

  return (min + max) / 2 + 1;
}

