 48→  for (int i = 0; i < matterCenter->getPositionsFree().rows(); ++i) {
 49→    for (int j = 0; j < matterCenter->getPositionsFree().cols(); ++j) {
 50→      R_init[counter++] = matterCenter->getPositionsFree()(i, j);
 51→    }
 52→  }
 53→  init_middle_point.clear();
 54→  init_middle_point.R = R_init;
 55→  init_observations.clear();
 56→  problem_setup.activateFrozenAtoms(
 57→      R_init, params.gpr_dimer_options.active_radius, atoms_config);
 58→  orient_init.clear();
 59→  orient_init.resize(matterCenter->getPositionsFree().rows(),
 60→                     matterCenter->getPositionsFree().cols());
 61→  AtomMatrix freeOrient(matterCenter->numberOfFreeAtoms(), 3);
 62→  int i, j = 0;
 63→  for (i = 0; i < matterCenter->numberOfAtoms(); i++) {
 64→    if (!matterCenter->getFixed(i)) {
 65→      freeOrient.row(j) = initialDirectionAtomMatrix.row(i);
 66→      j++;
 67→      if (j == matterCenter->numberOfFixedAtoms()) {
 68→        break;
 69→      }
 70→    }
 71→  }
 72→  // orient_init.assignFromEigenMatrix(freeOrient);
 73→  orient_init.resize(1, freeOrient.rows() * freeOrient.cols());
 74→  counter = 0;
 75→  for (int i = 0; i < freeOrient.rows(); ++i) {
 76→    for (int j = 0; j < freeOrient.cols(); ++j) {
 77→      orient_init[counter++] = freeOrient(i, j);
 78→    }
 79→  }
 80→  atomic_dimer.initialize(p, init_observations, init_middle_point, orient_init,
 81→                          atoms_config);
 82→
 83→  // Potential *potential = Potential::getPotential(parameters);
 84→  auto potential = helper_functions::makePotential(params);
 85→  eonc::FPEHandler fpeh;
 86→  fpeh.eat_fpe();
 87→  atomic_dimer.execute(*potential.get());
 88→  fpeh.restore_fpe();
 89→  // Forcefully set the right positions
 90→  matter->setPositionsFreeV(atomic_dimer.getFinalCoordOfMidPoint());
 91→  this->totalIterations = atomic_dimer.getIterations();
 92→  this->totalForceCalls = atomic_dimer.getTotalForceCalls();
 93→  pot->forceCallCounter = atomic_dimer.getTotalForceCalls();
 94→  return;
 95→}
