530→    void resize(const Index_t num_atoms)
531→    {
532→        positions.resize(1, num_atoms * 3);
533→        positions.setZero();
534→        type.resize(1, num_atoms);
535→        type.setZero();
536→    }
537→
538→    void clear()
539→    {
540→        positions.resize(0, 0);
541→        type.resize(0, 0);
542→    }
543→};
