545→/**
546→ * @brief Stores configurations of all atoms in the system.
547→ */
548→struct AtomsConfiguration {
549→    Coord positions;          //!< Positions of all atoms in the system
550→    FieldMatrixU8 is_frozen;  //!< Indicates whether atom is frozen or not
551→    FieldMatrixIdx id;        //!< ID of each atom (we do not use it)
552→    FieldMatrixi atomicNrs;   //!< Atomic Number of each atom
553→    FieldMatrixIdx type;      //!< Type of each atom
554→
555→    AtomsPositionAndType atoms_froz_active;  //!< Info on active frozen atoms
556→    AtomsPositionAndType
557→        atoms_froz_inactive;         //!< Info on inactive frozen atoms
558→    AtomsPositionAndType atoms_mov;  //!< Info on moving atoms
559→
560→    FieldMatrixi
561→        pairtype;  //!< Pairtype indices for pairs of  atomtypes (n_at x n_at).
562→                   //!< Active pairtypes are indexed as 0,1,2,...,n_pt-1.
563→                   //!< Inactive pairtypes are given index -1.
564→    Index_t n_pt;  //!< Number of active pairtypes
565→
566→    /**
567→     * @brief Extract data from a 5-column \e field.
568→     */
569→    void assignFromField(const FieldMatrixd& field)
570→    {
571→#ifndef NDEBUG
572→        assertMsg(field.size() != 0, "The reference field cannot be empty!");
573→        assertMsg(field.cols() >= 5,
574→                  "The reference field should have 5 or more columns!");
575→#endif
576→
577→        Index_t counter = 0;
578→
579→        positions.resize(1, 3 * field.rows());
580→        positions.setZero();
581→        is_frozen.resize(1, field.rows());
582→        is_frozen.setZero();
583→        id.resize(1, field.rows());
584→        id.setZero();
585→
586→        for (Eigen::Index i = 0; i < field.rows(); ++i) {
587→            for (Eigen::Index j = 0; j < 3; ++j) {
588→                *(positions.data() + counter++) = field(i, j);
589→            }
590→            if (field(i, 3) == 0)
591→                *(is_frozen.data() + i) = MOVING_ATOM;
592→            else
593→                *(is_frozen.data() + i) = FROZEN_ATOM;
594→            *(id.data() + i) = static_cast<Index_t>(field(i, 4));
595→        }
596→    }
597→
598→    void clear()
599→    {
600→        positions.resize(0, 0);
601→        is_frozen.resize(0, 0);
602→        id.resize(0, 0);
603→        atoms_froz_active.clear();
604→        atoms_froz_inactive.clear();
605→        atoms_mov.clear();
606→        pairtype.resize(0, 0);
607→        n_pt = 0;
608→    }
609→
610→    void clearDistribution()
611→    {
612→        atoms_froz_active.clear();
613→        atoms_froz_inactive.clear();
614→        atoms_mov.clear();
615→        pairtype.resize(0, 0);
616→        n_pt = 0;
617→    }
618→
619→    void copy(const AtomsConfiguration& other)
620→    {
621→        positions = other.positions;
622→        is_frozen = other.is_frozen;
623→        id = other.id;
624→        atoms_froz_active = other.atoms_froz_active;
625→        atoms_froz_inactive = other.atoms_froz_inactive;
626→        atoms_mov = other.atoms_mov;
627→        pairtype = other.pairtype;
628→        n_pt = other.n_pt;
629→    }
630→
631→    Index_t countMovingAtoms()
632→    {
633→        Index_t count = 0;
634→        for (Eigen::Index i = 0; i < is_frozen.size(); ++i) {
635→            if (*(is_frozen.data() + i) == MOVING_ATOM) ++count;
636→        }
637→        return count;
638→    }
639→};
