 14→inline double AtomicDimer::calculateCurvature(
 15→    const gpr::Coord& orient, const gpr::Observation& approx_obs)
 16→{
 17→    double curvature = 0.;
 18→
 19→    for (gpr::Index_t j = 0; j < approx_obs.G.cols(); ++j) {
 20→        curvature += (approx_obs.G(1, j) - approx_obs.G(0, j)) * orient(0, j);
 21→    }
 22→    curvature /= dimer_sep;
 23→
 24→    return curvature;
 25→}
